bash_commands.command:
cat > /tmp/test_scenario.json << 'EOF'
{
  "type": "table",
  "title": "Table without explicit defaults.custom but with overrides",
  "fieldConfig": {
    "defaults": {
      "custom": null
    },
    "overrides": [
      {
        "matcher": { "id": "byName", "options": "CPU" },
        "properties": [
          {
            "id": "custom.displayMode",
            "value": "color-background-solid"
          }
        ]
      }
    ]
  }
}
EOF
cat /tmp/test_scenario.json

